        code: '<demo-page-layout testId="orders-page">\n  <demo-navigation-strip demoNavigation testId="orders-demo-navigation" [demo]="demo" />\n\n  <article demoIntro class="demo-card demo-card--stack" data-testid="orders-controls-card">\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular URL State</p>\n        <h2>Orders search with shareable filters.</h2>\n      </div>\n\n      <div class="orders-actions">\n        <button\n          type="button"\n          class="demo-button demo-button--ghost"\n          data-testid="orders-reset-filters"\n          (click)="resetFilters()"\n        >\n          Reset filters\n        </button>\n      </div>\n    </div>\n\n    <p class="demo-card__summary">\n      Search, status, page, page size, and tag filters stay aligned with the URL while the component\n      keeps descriptive local state names. Compact query keys such as `q`, `p`, `size`, and repeated\n      `tag` values keep shared links short.\n    </p>\n\n    <div class="orders-controls-grid">\n      <label class="demo-field">\n        <span>Search</span>\n        <input\n          type="search"\n          class="demo-input"\n          [ngModel]="state.searchText()"\n          (ngModelChange)="updateSearch($event)"\n          placeholder="Customer, region, or order ID"\n          data-testid="orders-search-input"\n        />\n      </label>\n\n      <label class="demo-field">\n        <span>Status</span>\n        <select\n          class="demo-select"\n          [ngModel]="state.statusFilter()"\n          (ngModelChange)="updateStatus($event)"\n          data-testid="orders-status-select"\n        >\n          @for (status of statusOptions; track status) {\n            <option [value]="status">{{ status }}</option>\n          }\n        </select>\n      </label>\n\n      <label class="demo-field">\n        <span>Page</span>\n        <input\n          type="number"\n          min="1"\n          class="demo-input"\n          [ngModel]="state.pageNumber()"\n          (ngModelChange)="updatePageNumber($event)"\n          data-testid="orders-page-input"\n        />\n      </label>\n\n      <label class="demo-field">\n        <span>Page size</span>\n        <select\n          class="demo-select"\n          [ngModel]="state.pageSize()"\n          (ngModelChange)="updatePageSize($event)"\n          data-testid="orders-page-size-select"\n        >\n          @for (size of pageSizeOptions; track size) {\n            <option [value]="size">{{ size }} rows</option>\n          }\n        </select>\n      </label>\n\n      <label class="demo-field orders-field--wide">\n        <span>Tags</span>\n        <input\n          type="text"\n          class="demo-input"\n          [ngModel]="tagValue()"\n          (ngModelChange)="updateTags($event)"\n          placeholder="priority, enterprise"\n          data-testid="orders-tags-input"\n        />\n      </label>\n    </div>\n\n    <demo-status-strip\n      testId="orders-status-strip"\n      summaryTestId="orders-result-summary"\n      urlTestId="orders-current-url"\n      [summary]="resultSummary()"\n      [currentUrl]="currentUrl()"\n    />\n  </article>\n\n  <article demoPrimary class="demo-card demo-card--stack" data-testid="orders-table-card">\n    <div class="orders-table-head">\n      <div>\n        <p class="demo-eyebrow">Shareable URL</p>\n        <h3>Orders state</h3>\n      </div>\n      <div class="orders-pager">\n        <button\n          type="button"\n          class="demo-button demo-button--ghost"\n          data-testid="orders-previous-page"\n          (click)="goToPage(currentPage() - 1)"\n        >\n          Previous\n        </button>\n        <span data-testid="orders-page-indicator"\n          >Page {{ currentPage() }} of {{ totalPages() }}</span\n        >\n        <button\n          type="button"\n          class="demo-button demo-button--ghost"\n          data-testid="orders-next-page"\n          (click)="goToPage(currentPage() + 1)"\n        >\n          Next\n        </button>\n      </div>\n    </div>\n\n    <div class="orders-table-wrap" data-testid="orders-table-wrap">\n      <table class="orders-table" data-testid="orders-table">\n        <thead>\n          <tr>\n            <th>Order</th>\n            <th>Customer</th>\n            <th>Region</th>\n            <th>Age</th>\n            <th>Total</th>\n            <th>Tags</th>\n          </tr>\n        </thead>\n        <tbody>\n          @for (record of pagedOrders(); track record.id) {\n            <tr data-testid="orders-row">\n              <td>\n                <strong>{{ record.id }}</strong>\n                <span class="orders-status-chip">{{ record.status }}</span>\n              </td>\n              <td>{{ record.customer }}</td>\n              <td>{{ record.region }}</td>\n              <td>{{ record.ageDays }}d</td>\n              <td>{{ currency(record.total) }}</td>\n              <td>{{ record.tags.join(\', \') }}</td>\n            </tr>\n          } @empty {\n            <tr>\n              <td colspan="6" class="orders-empty-state" data-testid="orders-empty-state">\n                No rows matched the current combination of query parameters.\n              </td>\n            </tr>\n          }\n        </tbody>\n      </table>\n    </div>\n  </article>\n\n  <demo-inspector-panel\n    demoAside\n    panelTestId="orders-inspector-panel"\n    snapshotTestId="orders-snapshot-json"\n    codeTestId="orders-code-sample"\n    title="Live state and source"\n    summary="Switch between the live state snapshot and the generated source excerpt that powers this demo."\n    [snapshotJson]="snapshotJson()"\n    [docsLinks]="demo.docsLinks"\n    [snippetId]="demo.codeSample.snippetId"\n  />\n</demo-page-layout>',
